// modules/menu-generator/index.js
async processMenuImage(imageBase64) {
  // Este módulo SABE que para menús, Google Vision funciona mejor
  const result = await this.sendRequest(
    'google.vision.extract.request',
    'google.vision.extract.response',
    { image: imageBase64, hint: 'DOCUMENT_TEXT_DETECTION' }
  );

  return this.parseMenuText(result.data.text);
}

// modules/invoice-processor/index.js  
async processInvoice(imageBase64) {
  // Este módulo SABE que para facturas, Anthropic entiende mejor la estructura
  const result = await this.sendRequest(
    'anthropic.vision.extract.request',
    'anthropic.vision.extract.response',
    { image: imageBase64, prompt: 'Extrae: emisor, CIF, total, fecha, líneas' }
  );

  return result.data;
}

